import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { getProjects, createProject, deleteProject } from '../utils/api';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { format } from 'date-fns';

export default function Projects() {
  const { isAdmin } = useAuth();
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [form, setForm] = useState({ name: '', description: '', deadline: '' });
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    fetchProjects();
  }, []);

  const fetchProjects = async () => {
    try {
      const res = await getProjects();
      setProjects(res.data.projects);
    } catch {
      toast.error('Failed');
    } finally {
      setLoading(false);
    }
  };

  const handleCreate = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      await createProject(form);
      await fetchProjects();
      setShowModal(false);
      setForm({ name: '', description: '', deadline: '' });
      toast.success('Created!');
    } catch {
      toast.error('Failed');
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete project?')) return;
    try {
      await deleteProject(id);
      await fetchProjects();
      toast.success('Deleted');
    } catch {
      toast.error('Failed');
    }
  };

  if (loading) return <div style={{textAlign:'center',padding:'60px',color:'#fff'}}>Loading...</div>;

  return (
    <div style={{minHeight:'100vh',padding:'30px',background:'linear-gradient(135deg,#0f172a,#022c22)'}}>

      {/* HEADER */}
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'25px'}}>
        <h1 style={{fontSize:'32px',color:'#4ade80'}}>Projects</h1>

        {isAdmin && (
          <button onClick={() => setShowModal(true)}
            style={{padding:'10px 16px',background:'#22c55e',border:'none',borderRadius:'8px',color:'#022c22',fontWeight:'600'}}>
            + New Project
          </button>
        )}
      </div>

      {/* LIST */}
      {projects.length === 0 ? (
        <p style={{textAlign:'center',color:'#9ca3af'}}>
          {isAdmin ? 'Create your first project' : 'No projects'}
        </p>
      ) : (
        <div style={{display:'grid',gridTemplateColumns:'repeat(2,1fr)',gap:'20px'}}>
          {projects.map(p => (
            <div key={p._id} style={{
              background:'rgba(255,255,255,0.06)',
              padding:'18px',
              borderRadius:'12px',
              border:'1px solid rgba(255,255,255,0.1)'
            }}>

              {/* TOP */}
              <div style={{display:'flex',justifyContent:'space-between',marginBottom:'8px'}}>
                <div style={{fontSize:'16px',fontWeight:'600',color:'#fff'}}>
                  {p.name}
                </div>

                {isAdmin && (
                  <button onClick={() => handleDelete(p._id)}
                    style={{background:'none',border:'none',color:'#f87171',cursor:'pointer'}}>
                    🗑
                  </button>
                )}
              </div>

              {/* DESC */}
              {p.description && (
                <div style={{fontSize:'13px',color:'#9ca3af',marginBottom:'10px'}}>
                  {p.description}
                </div>
              )}

              {/* INFO */}
              <div style={{fontSize:'12px',color:'#bbf7d0',marginBottom:'10px'}}>
                👥 {p.members?.length || 0} members
              </div>

              {p.deadline && (
                <div style={{fontSize:'12px',color:'#9ca3af',marginBottom:'12px'}}>
                  📅 {format(new Date(p.deadline),'MMM dd, yyyy')}
                </div>
              )}

              {/* ACTION */}
              <Link to={`/projects/${p._id}`}
                style={{fontSize:'13px',color:'#4ade80',textDecoration:'none'}}>
                View →
              </Link>

            </div>
          ))}
        </div>
      )}

      {/* MODAL */}
      {showModal && (
        <div onClick={e => e.target === e.currentTarget && setShowModal(false)}
          style={{
            position:'fixed',
            top:0,left:0,right:0,bottom:0,
            background:'rgba(0,0,0,0.6)',
            display:'flex',
            alignItems:'center',
            justifyContent:'center'
          }}>

          <div style={{
            background:'#111827',
            padding:'25px',
            borderRadius:'12px',
            width:'100%',
            maxWidth:'400px'
          }}>

            <h2 style={{color:'#4ade80',marginBottom:'15px'}}>New Project</h2>

            <form onSubmit={handleCreate}>

              <input
                placeholder="Project name"
                value={form.name}
                onChange={e => setForm({...form,name:e.target.value})}
                required
                style={{width:'100%',padding:'10px',marginBottom:'10px',borderRadius:'6px',border:'1px solid #374151',background:'#020617',color:'#fff'}}
              />

              <textarea
                rows={3}
                placeholder="Description"
                value={form.description}
                onChange={e => setForm({...form,description:e.target.value})}
                style={{width:'100%',padding:'10px',marginBottom:'10px',borderRadius:'6px',border:'1px solid #374151',background:'#020617',color:'#fff'}}
              />

              <input
                type="date"
                value={form.deadline}
                onChange={e => setForm({...form,deadline:e.target.value})}
                style={{width:'100%',padding:'10px',marginBottom:'15px',borderRadius:'6px',border:'1px solid #374151',background:'#020617',color:'#fff'}}
              />

              <div style={{display:'flex',gap:'10px'}}>
                <button type="button" onClick={() => setShowModal(false)}
                  style={{flex:1,padding:'10px',background:'#374151',border:'none',borderRadius:'6px',color:'#fff'}}>
                  Cancel
                </button>

                <button type="submit" disabled={saving}
                  style={{flex:1,padding:'10px',background:'#22c55e',border:'none',borderRadius:'6px',color:'#022c22'}}>
                  {saving ? 'Creating...' : 'Create'}
                </button>
              </div>

            </form>

          </div>
        </div>
      )}

    </div>
  );
}
